     1→import type { StateCreator } from 'zustand';
     2→import {
     3→  PointsExtractStatus,
     4→  PointsBalanceStatus,
     5→  type PointsExtractState,
     6→  type PointsBalanceState,
     7→  type PointsExtractFiltersState,
     8→  type PointsExtractData,
     9→  type ProcessedExtractData,
    10→  type AppliedFilters,
    11→  type ExpiringFilters,
    12→} from '../models';
    13→
    14→export interface PointsExtractActions {
    15→  setExtractStatus: (status: PointsExtractStatus) => void;
    16→  setExtractData: (extractData: PointsExtractData, processedExtractData?: ProcessedExtractData) => void;
    17→  appendExtractData: (extractData: PointsExtractData, processedExtractData?: ProcessedExtractData) => void;
    18→  setLoadingMore: (isLoading: boolean) => void;
    19→  setBalanceStatus: (status: PointsBalanceStatus) => void;
    20→  setBalance: (points?: number) => void;
    21→  setTransactionsFilters: (filters: AppliedFilters) => void;
    22→  clearTransactionsFilters: () => void;
    23→  setExpiringFilters: (filters: ExpiringFilters) => void;
    24→  clearExpiringFilters: () => void;
    25→  reset: () => void;
    26→}
    27→
    28→export interface PointsExtractSlice {
    29→  pointsExtract: PointsExtractState;
    30→  pointsBalance: PointsBalanceState;
    31→  pointsExtractFilters: PointsExtractFiltersState;
    32→  pointsExtractActions: PointsExtractActions;
    33→}
    34→
    35→const INITIAL_POINTS_EXTRACT_STATE: PointsExtractState = {
    36→  extractData: undefined,
    37→  processedExtractData: undefined,
    38→  status: PointsExtractStatus.IDLE,
    39→  isLoadingMore: false,
    40→  error: undefined,
    41→};
    42→
    43→const INITIAL_POINTS_BALANCE_STATE: PointsBalanceState = {
    44→  points: undefined,
    45→  status: PointsBalanceStatus.IDLE,
    46→  error: undefined,
    47→};
    48→
    49→const INITIAL_POINTS_EXTRACT_FILTERS_STATE: PointsExtractFiltersState = {
    50→  appliedTransactionsFilters: undefined,
    51→  appliedExpiringFilters: undefined,
    52→};
    53→
    54→export const createPointsExtractSlice: StateCreator<
    55→  PointsExtractSlice,
    56→  [],
    57→  [],
    58→  PointsExtractSlice
    59→> = (set) => ({
    60→  pointsExtract: INITIAL_POINTS_EXTRACT_STATE,
    61→  pointsBalance: INITIAL_POINTS_BALANCE_STATE,
    62→  pointsExtractFilters: INITIAL_POINTS_EXTRACT_FILTERS_STATE,
    63→  pointsExtractActions: {
    64→    setExtractStatus: (status) =>
    65→      set((state) => ({
    66→        pointsExtract: { 
    67→          ...state.pointsExtract, 
    68→          status,
    69→          ...(status === PointsExtractStatus.IDLE || status === PointsExtractStatus.LOADING ? { error: undefined } : {}),
    70→        },
    71→      })),
    72→    setExtractData: (extractData, processedExtractData) =>
    73→      set((state) => ({
    74→        pointsExtract: {
    75→          ...state.pointsExtract,
    76→          extractData,
    77→          processedExtractData,
    78→          status: PointsExtractStatus.SUCCESS,
    79→          isLoadingMore: false,
    80→          error: undefined,
    81→        },
    82→      })),
    83→    appendExtractData: (extractData, processedExtractData) =>
    84→      set((state) => {
    85→        const existingTransactions = state.pointsExtract.extractData?.transactions ?? [];
    86→        const newTransactions = extractData.transactions;
    87→        const mergedTransactions = [...existingTransactions, ...newTransactions];
    88→
    89→        const existingProcessed = state.pointsExtract.processedExtractData;
    90→        const newProcessed = processedExtractData;
    91→
    92→        let mergedProcessed: ProcessedExtractData | undefined;
    93→        if (existingProcessed && newProcessed) {
    94→          const existingMapped = existingProcessed.mappedTransactions ?? [];
    95→          const newMapped = newProcessed.mappedTransactions ?? [];
    96→          mergedProcessed = {
    97→            groupedTransactions: newProcessed.groupedTransactions,
    98→            mappedTransactions: [...existingMapped, ...newMapped],
    99→          };
   100→        } else {
   101→          mergedProcessed = newProcessed ?? existingProcessed;
   102→        }
   103→
   104→        return {
   105→          pointsExtract: {
   106→            ...state.pointsExtract,
   107→            extractData: {
   108→              transactions: mergedTransactions,
   109→              pagination: extractData.pagination,
   110→            },
   111→            processedExtractData: mergedProcessed,
   112→            isLoadingMore: false,
   113→          },
   114→        };
   115→      }),
   116→    setLoadingMore: (isLoading) =>
   117→      set((state) => ({
   118→        pointsExtract: { ...state.pointsExtract, isLoadingMore: isLoading },
   119→      })),
   120→    setBalanceStatus: (status) =>
   121→      set((state) => ({
   122→        pointsBalance: { ...state.pointsBalance, status },
   123→      })),
   124→    setBalance: (points) =>
   125→      set((state) => ({
   126→        pointsBalance: {
   127→          ...state.pointsBalance,
   128→          points,
   129→          status: PointsBalanceStatus.SUCCESS,
   130→          error: undefined,
   131→        },
   132→      })),
   133→    setTransactionsFilters: (filters) =>
   134→      set((state) => ({
   135→        pointsExtractFilters: {
   136→          ...state.pointsExtractFilters,
   137→          appliedTransactionsFilters: filters,
   138→        },
   139→      })),
   140→    clearTransactionsFilters: () =>
   141→      set((state) => ({
   142→        pointsExtractFilters: {
   143→          ...state.pointsExtractFilters,
   144→          appliedTransactionsFilters: undefined,
   145→        },
   146→      })),
   147→    setExpiringFilters: (filters) =>
   148→      set((state) => ({
   149→        pointsExtractFilters: {
   150→          ...state.pointsExtractFilters,
   151→          appliedExpiringFilters: filters,
