  PointsProductsSlice,
  [],
  [],
  PointsProductsSlice
> = (set) => ({
  pointsProducts: initialPointsProductsState,

  pointsProductsActions: {
    setStatus: (status) =>
      set((state) => ({
        pointsProducts: {
          ...state.pointsProducts,
          status,
          ...(status === PointsProductsStatus.LOADING && {
            error: undefined,
          }),
        },
      })),

    setProducts: (products) =>
      set((state) => ({
        pointsProducts: {
          ...state.pointsProducts,
          products,
          status: PointsProductsStatus.SUCCESS,
          error: undefined,
        },
      })),

    setError: (error) =>
      set((state) => ({
        pointsProducts: {
          ...state.pointsProducts,
          error,
        },
      })),

    reset: () =>
      set({
        pointsProducts: initialPointsProductsState,
      }),
  },
});

